UPDATE pms_sku_stock SET stock = CASE id
WHEN #{item.productSkuId} THEN stock - #{item.productQuantity}
END, lock_stock = CASE id
WHEN #{item.productSkuId} THEN lock_stock - #{item.productQuantity}
END WHERE id IN
#{item.productSkuId}

UPDATE pms_product p INNER JOIN ( SELECT product_id, SUM(product_quantity) AS quantity FROM (
SELECT #{item.productId} AS product_id, #{item.productQuantity} AS product_quantity
) order_items WHERE product_id IS NOT NULL GROUP BY product_id ) oi ON p.id = oi.product_id SET p.sale = IFNULL(p.sale, 0) + oi.quantity, p.stock = CASE WHEN EXISTS (SELECT 1 FROM pms_sku_stock s WHERE s.product_id = p.id) THEN (SELECT IFNULL(SUM(s.stock), 0) FROM pms_sku_stock s WHERE s.product_id = p.id) ELSE GREATEST(IFNULL(p.stock, 0) - oi.quantity, 0) END

update oms_order
set status=#{status}
where id in

    #{id}

UPDATE pms_sku_stock SET lock_stock = CASE id
WHEN #{item.productSkuId} THEN lock_stock - #{item.productQuantity}
END WHERE id IN
#{item.productSkuId}
